import{_ as t,W as e,X as i,Y as a}from"./framework-9a5142fa.js";const n={},o=a('<h2 id="取消防火墙" tabindex="-1"><a class="header-anchor" href="#取消防火墙" aria-hidden="true">#</a> 取消防火墙</h2><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202406231912742.png" alt="alt text"></p><h2 id="没试过-允许应用通过防火墙" tabindex="-1"><a class="header-anchor" href="#没试过-允许应用通过防火墙" aria-hidden="true">#</a> 没试过：允许应用通过防火墙</h2><p>以win10为例，进入控制面板-系统和安全-Windows Defender 防火墙-高级设置，进入高级安全设置，如下图所示。然后点击3处，设置防火墙属性，如果发现出现的页面和下图右侧不同，可以点击2处回到此显示页面。</p><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202406231913263.png" alt="image-20210428135711577"></p><p>虚拟机与真实主机属于局域网，因此首先需要在&quot;专用配置文件&quot;页将&quot;入站连接&quot;选择为&quot;允许&quot;，表示允许局域网其他主机绕过防火墙访问本机。点击确定。</p><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202406231913027.png" alt="image-20210428140441453"></p><p>但此时可能仍然无法ping通，我们再点击入站规则，在右侧找到&quot;文件和打印共享（回显请求 – ICMPv4-In)&quot;项，&quot;回显请求&quot;，指的就是ping请求的回显响应吧。如下图，设置之前，1处应该是&quot;否&quot;，2处应该是&quot;启用规则&quot;，点击&quot;启用规则&quot;，就会变成下图的样子了，注意文件和打印共享之回显请求一共有4项，IPV4和IPV6各两项，每个下面包括&quot;域&quot;和“专用，公用”，我们要选择IPV4和&quot;专用，公用&quot;的那项，不要弄错。</p><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202406231913427.png" alt="image-20210428141204559"></p><p>完成上述操作之后，就会惊喜地发现，可以用虚拟机ping通真实主机地址啦，而且不用关闭windows防火墙！</p>',10),s=[o];function p(r,c){return e(),i("div",null,s)}const u=t(n,[["render",p],["__file","防火墙.html.vue"]]);export{u as default};
